import React, { useState } from "react";
import { useTranslation } from "react-i18next";
import { theme, Tabs, Typography, Select, Space, Card, Flex, Breadcrumb } from "antd";
import { 
  SafetyOutlined, 
  PartitionOutlined,
  DashboardOutlined,
  ProjectOutlined,
  HomeOutlined
} from "@ant-design/icons";

import QualityDashboard from "./QualityDashboard";
import AccuracyAnalysis from "./AccuracyAnalysis";
import VarietyAnalysis from "./VarietyAnalysis";

const { useToken } = theme;
const { Title, Text } = Typography;

export default function QualityPage() {
  const { token } = useToken();
  const { t } = useTranslation(["quality", "common", "project"]);
  const [activeTab, setActiveTab] = useState("dashboard");
  const [projectId, setProjectId] = useState("1"); // Default: Autonomous Driving

  const projectOptions = [
    { value: "1", label: "자율주행 - 도심 도로 주행 데이터" },
    { value: "2", label: "CCTV 지능형 안전 통합 관제" },
    { value: "3", label: "의료 영상 판독용 AI 데이터셋" },
    { value: "4", label: "스마트 팩토리 안전화 인식" },
  ];

  const items = [
    {
      key: "dashboard",
      label: (
        <span>
          <DashboardOutlined />
          {t("tabs.dashboard")}
        </span>
      ),
      children: <QualityDashboard projectId={projectId} />,
    },
    {
      key: "accuracy",
      label: (
        <span>
          <SafetyOutlined />
          {t("tabs.accuracy")}
        </span>
      ),
      children: <AccuracyAnalysis projectId={projectId} />,
    },
    {
      key: "variety",
      label: (
        <span>
          <PartitionOutlined />
          {t("tabs.variety")}
        </span>
      ),
      children: <VarietyAnalysis projectId={projectId} />,
    },
  ];

  return (
    <div style={{ padding: "0 24px 24px 24px", minHeight: "100%" }}>
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-end", marginBottom: 20 }}>
        <div>
          <Title level={4} style={{ margin: 0 }}>{t("title")}</Title>
          <Text type="secondary" style={{ fontSize: 12 }}>{t("subtitle")}</Text>
        </div>
        <Flex vertical align="flex-end" gap={8}>
          <Breadcrumb 
            items={[
              { title: <Space><HomeOutlined /> {t("listPage.home", { ns: "labeling" })}</Space> },
              { title: t("title") }
            ]} 
          />
          <Flex align="center" gap={12}>
            <Text type="secondary" style={{ fontSize: 13, fontWeight: 500 }}>
              {t("modal.prjNm", { ns: "project" })} {t("select", { ns: "common" })}
            </Text>
            <Select 
              size="small"
              style={{ width: 260 }} 
              value={projectId} 
              onChange={setProjectId}
              options={projectOptions}
              prefix={<ProjectOutlined style={{ color: token.colorPrimary }} />}
              variant="filled"
            />
          </Flex>
        </Flex>
      </div>

      <Tabs 
        activeKey={activeTab} 
        onChange={setActiveTab} 
        items={items}
        type="line"
        size="large"
        style={{ background: token.colorBgContainer, padding: "0 20px 20px 20px", borderRadius: 12, boxShadow: token.boxShadowTertiary }}
      />
    </div>
  );
}
