import React, { useMemo } from "react";
import { useTranslation } from "react-i18next";
import { Row, Col, Card, Table, Typography, theme, Space, Tag } from "antd";
import { PartitionOutlined, PieChartOutlined, BarChartOutlined, RadarChartOutlined } from "@ant-design/icons";
import ReactECharts from "echarts-for-react";

const { useToken } = theme;
const { Title, Text } = Typography;

interface Props {
  projectId: string;
}

const getVarietyTableData = (projectId: string, classes: string[]) => {
  return classes.map((cls, idx) => {
    const counts: Record<string, number[]> = {
      "1": [5200, 4200, 1500, 800, 400, 350, 2100, 1800],
      "2": [12000, 15, 22, 140, 850, 45],
      "3": [8500, 420, 120, 85, 30],
      "4": [1250, 320, 5400, 820, 2100],
    };
    const projectCounts = counts[projectId] || [100];
    const count = projectCounts[idx] || 100;
    const total = projectCounts.reduce((a, b) => a + b, 0);
    const ratio = ((count / total) * 100).toFixed(1) + "%";
    
    return { key: `${projectId}_${idx}`, category: cls, count, ratio };
  });
};

const VarietyAnalysis: React.FC<Props> = ({ projectId }) => {
  const { token } = useToken();
  const { t } = useTranslation(["commonCodes", "quality", "common"]);

  const classes = useMemo(() => {
    const res = t(`PROJECT_CLASSES.${projectId}`, { ns: "commonCodes", returnObjects: true });
    return Array.isArray(res) ? res : [];
  }, [projectId, t]);

  const tableData = useMemo(() => getVarietyTableData(projectId, classes), [projectId, classes]);

  const envLabels = useMemo(() => {
    if (projectId === "3") return [t("ENVIRONMENT.LOCATION.LAB"), t("ENVIRONMENT.LOCATION.INDOOR"), t("ENVIRONMENT.WEATHER.SUNNY")];
    if (projectId === "2") return [t("ENVIRONMENT.TIME.NIGHT"), t("ENVIRONMENT.TIME.DAWN"), t("ENVIRONMENT.LOCATION.URBAN")];
    return [t("ENVIRONMENT.TIME.DAY"), t("ENVIRONMENT.TIME.NIGHT"), t("ENVIRONMENT.WEATHER.RAIN"), t("ENVIRONMENT.WEATHER.FOG"), t("ENVIRONMENT.LOCATION.TUNNEL")];
  }, [projectId, t]);

  const barOption = useMemo(() => {
    const distributionData: Record<string, number[]> = { "1": [1200, 800, 450, 120, 300], "2": [950, 200, 1100], "3": [8000, 1500, 500], "4": [700, 100, 50] };
    return {
      tooltip: { trigger: 'axis', axisPointer: { type: 'shadow' } },
      grid: { left: '3%', right: '4%', bottom: '3%', containLabel: true },
      xAxis: { type: 'value' },
      yAxis: { type: 'category', data: envLabels, axisLabel: { color: token.colorText } },
      series: [{
        name: t("variety.distribution", { ns: "quality" }),
        type: 'bar',
        data: distributionData[projectId] || [100],
        itemStyle: { color: token.colorPrimary, borderRadius: [0, 4, 4, 0] }
      }]
    };
  }, [projectId, envLabels, token, t]);

  const envRadarOption = useMemo(() => {
    const radarData: Record<string, number[]> = { "1": [1200, 800, 450, 120, 300], "2": [950, 200, 1100], "3": [8000, 1500, 500], "4": [700, 100, 50] };
    return {
      radar: { indicator: envLabels.map(name => ({ name, max: projectId === "3" ? 10000 : 2000 })), shape: 'circle' },
      series: [{
        type: 'radar',
        data: [{ value: radarData[projectId] || [100], name: 'Env Distribution' }],
        areaStyle: { opacity: 0.3, color: token.colorInfo },
        lineStyle: { width: 2, color: token.colorInfo }
      }]
    };
  }, [projectId, envLabels, token]);

  const classRadarOption = useMemo(() => {
    return {
      radar: { indicator: classes.slice(0, 6).map(cls => ({ name: cls, max: projectId === "3" ? 10000 : (projectId === "2" ? 15000 : 6000) })), shape: 'circle' },
      series: [{
        type: 'radar',
        data: [{ value: tableData.slice(0, 6).map(d => d.count), name: 'Class Distribution' }],
        areaStyle: { opacity: 0.3, color: token.colorSuccess },
        lineStyle: { width: 2, color: token.colorSuccess }
      }]
    };
  }, [projectId, classes, tableData, token]);

  return (
    <div style={{ marginTop: 24 }}>
      <Row gutter={[24, 24]}>
        <Col span={14}>
          <Card variant="borderless" title={<Space><BarChartOutlined /> {t("variety.distribution", { ns: "quality" })} ({t("ENVIRONMENT.title")})</Space>}>
            <ReactECharts option={barOption} style={{ height: 300 }} />
          </Card>
        </Col>
        <Col span={10}>
          <Card variant="borderless" title={<Space><RadarChartOutlined /> {t("variety.balanceEnv", { ns: "quality" })}</Space>}>
            <ReactECharts option={envRadarOption} style={{ height: 300 }} />
          </Card>
        </Col>

        <Col span={14}>
          <Card variant="borderless" title={<Space><PartitionOutlined /> {t("variety.title", { ns: "quality" })}</Space>}>
            <Table 
              size="small"
              dataSource={tableData}
              pagination={false}
              columns={[
                { title: t("variety.category", { ns: "quality" }), dataIndex: "category" },
                { title: t("variety.count", { ns: "quality" }), dataIndex: "count", align: "right", render: v => v.toLocaleString() },
                { title: t("variety.ratio", { ns: "quality" }), dataIndex: "ratio", align: "right" }
              ]}
            />
          </Card>
        </Col>
        <Col span={10}>
          <Card variant="borderless" title={<Space><PieChartOutlined /> {t("variety.balanceClass", { ns: "quality" })}</Space>}>
            <ReactECharts option={classRadarOption} style={{ height: 300 }} />
          </Card>
        </Col>
      </Row>
    </div>
  );
};

export default VarietyAnalysis;
