import React, { useState, useMemo, useEffect } from "react";
import { useTranslation } from "react-i18next";
import { 
  Row, Col, Card, Table, Statistic, Space, 
  Progress, Tag, Typography, Button, theme 
} from "antd";
import { 
  CheckCircleOutlined, CloseCircleOutlined, 
  ClockCircleOutlined, SafetyOutlined,
  DownloadOutlined 
} from "@ant-design/icons";

const { useToken } = theme;
const { Title, Text } = Typography;

interface Props {
  projectId: string;
}

// --- Realistic Mock Data (Simulating legacy API response) ---
const getMockSummaryData = (t: any, projectId: string) => {
  const stats: Record<string, any> = {
    "1": { key: "total", quality: t("dashboard.statsTitle"), imgCnt: 500, pass: 420, fail: 20, badCnt: 6, passRate: 84.0 },
    "2": { key: "total", quality: t("dashboard.statsTitle"), imgCnt: 1200, pass: 1150, fail: 45, badCnt: 5, passRate: 95.8 },
    "3": { key: "total", quality: t("dashboard.statsTitle"), imgCnt: 12000, pass: 8000, fail: 400, badCnt: 100, passRate: 66.7 },
    "4": { key: "total", quality: t("dashboard.statsTitle"), imgCnt: 100, pass: 85, fail: 2, badCnt: 1, passRate: 85.0 },
  };
  return [stats[projectId] || stats["1"]];
};

const mockProjectQuality = [
  { key: "1", prjNm: "자율주행 - 도심 도로 주행 데이터", goalCnt: 500, workCnt: 446, pass: 420, fail: 20, badCnt: 6, passRate: 94.1, applyDt: "2026-04-05" },
  { key: "2", prjNm: "CCTV 지능형 안전 통합 관제", goalCnt: 1200, workCnt: 1200, pass: 1150, fail: 45, badCnt: 5, passRate: 95.8, applyDt: "2026-04-01" },
  { key: "3", prjNm: "의료 영상 판독용 AI 데이터셋", goalCnt: 12000, workCnt: 8500, pass: 8000, fail: 400, badCnt: 100, passRate: 94.1, applyDt: "2026-04-07" },
  { key: "4", prjNm: "스마트 팩토리 안전화 인식", goalCnt: 100, workCnt: 88, pass: 85, fail: 2, badCnt: 1, passRate: 96.5, applyDt: "2026-04-08" },
];

const mockHistory = [
  { key: "1", no: 1, date: "2026-04-08", inspector: "admin", pass: 85, fail: 2, badCnt: 1, passRate: "96.5%" },
  { key: "2", no: 2, date: "2026-04-07", inspector: "manager_01", pass: 8000, fail: 400, badCnt: 100, passRate: "94.1%" },
];

const QualityDashboard: React.FC<Props> = ({ projectId }) => {
  const { token } = useToken();
  const { t } = useTranslation(["quality", "common", "project"]);
  const [localSelectedPrj, setLocalSelectedPrj] = useState<string | null>(null);

  useEffect(() => {
    const prj = mockProjectQuality.find(p => p.key === projectId);
    if (prj) setLocalSelectedPrj(prj.prjNm);
  }, [projectId]);

  const stats = useMemo(() => getMockSummaryData(t, projectId)[0], [t, projectId]);

  return (
    <div style={{ marginTop: 24 }}>
      {/* 1. Overall Statistics Cards */}
      <Row gutter={[16, 16]} style={{ marginBottom: 24 }}>
        <Col span={6}>
          <Card variant="borderless" style={{ background: token.colorFillTertiary, height: "100%" }} styles={{ body: { height: "100%", display: "flex", flexDirection: "column", justifyContent: "space-between" } }}>
            <div>
              <Statistic 
                title={t("dashboard.passRate")} 
                value={stats.passRate} 
                precision={1}
                suffix="%" 
                prefix={<CheckCircleOutlined style={{ color: token.colorSuccess }} />} 
              />
            </div>
            <div style={{ marginTop: 12 }}>
              <Progress percent={stats.passRate} size="small" showInfo={false} strokeColor={token.colorSuccess} />
            </div>
          </Card>
        </Col>
        <Col span={6}>
          <Card variant="borderless" style={{ background: token.colorFillTertiary, height: "100%" }} styles={{ body: { height: "100%", display: "flex", flexDirection: "column", justifyContent: "space-between" } }}>
            <div>
              <Statistic 
                title={t("dashboard.inspectComplete")} 
                value={stats.pass + stats.fail} 
                suffix={t("unitCases", { ns: "common" })} 
                prefix={<SafetyOutlined style={{ color: token.colorInfo }} />} 
              />
            </div>
            <div style={{ marginTop: 12 }}>
              <Text type="secondary" style={{ fontSize: 11, display: "block" }}>{t("dashboard.inspectTarget")}: {stats.imgCnt.toLocaleString()}</Text>
            </div>
          </Card>
        </Col>
        <Col span={6}>
          <Card variant="borderless" style={{ background: token.colorFillTertiary, height: "100%" }} styles={{ body: { height: "100%", display: "flex", flexDirection: "column", justifyContent: "space-between" } }}>
            <div>
              <Statistic 
                title={t("dashboard.notChecked")} 
                value={stats.imgCnt - stats.pass - stats.fail} 
                suffix={t("unitCases", { ns: "common" })} 
                prefix={<ClockCircleOutlined style={{ color: token.colorWarning }} />} 
              />
            </div>
            <div style={{ marginTop: 12, height: 16 }}>
              {/* Spacer matching Progress/Text height */}
            </div>
          </Card>
        </Col>
        <Col span={6}>
          <Card variant="borderless" style={{ background: token.colorFillTertiary, height: "100%" }} styles={{ body: { height: "100%", display: "flex", flexDirection: "column", justifyContent: "space-between" } }}>
            <div>
              <Statistic 
                title={t("dashboard.failRate")} 
                value={((stats.fail / stats.imgCnt) * 100).toFixed(1)} 
                suffix="%" 
                prefix={<CloseCircleOutlined style={{ color: token.colorError }} />} 
              />
            </div>
            <div style={{ marginTop: 12 }}>
              <Progress percent={Number((stats.fail / stats.imgCnt) * 100)} size="small" showInfo={false} strokeColor={token.colorError} />
            </div>
          </Card>
        </Col>
      </Row>

      {/* 2. Main Tables */}
      <Row gutter={[24, 24]}>
        <Col span={16}>
          <Card 
            title={t("dashboard.prjTitle")} 
            extra={<Button size="small" icon={<DownloadOutlined />}>{t("export", { ns: "project" })}</Button>}
          >
            <Table 
              size="small" 
              dataSource={mockProjectQuality} 
              pagination={{ pageSize: 5 }}
              onRow={(record) => ({ 
                onClick: () => setLocalSelectedPrj(record.prjNm) 
              })}
              rowClassName={(record) => record.prjNm === localSelectedPrj ? "ant-table-row-selected" : ""}
              columns={[
                { title: t("modal.prjNm", { ns: "project" }), dataIndex: "prjNm", width: 250 },
                { title: t("columns.workCount", { ns: "project" }), dataIndex: "workCnt", align: "right", render: v => v.toLocaleString() },
                { title: t("accuracy.result.pass"), dataIndex: "pass", align: "right", render: v => <Text type="success">{v.toLocaleString()}</Text> },
                { title: t("accuracy.result.fail"), dataIndex: "fail", align: "right", render: v => <Text type="danger">{v.toLocaleString()}</Text> },
                { title: t("dashboard.passRate"), dataIndex: "passRate", align: "right", render: v => <Tag color="green">{v}%</Tag> },
                { title: t("dashboard.history.date"), dataIndex: "applyDt", width: 120 },
                { title: t("common.action"), align: "center" as const, render: () => <Button size="small" type="link">{t("view", { ns: "common" })}</Button> }
              ]}
            />
          </Card>
        </Col>

        <Col span={8}>
          <Card 
            title={t("dashboard.historyTitle")} 
            extra={<Text type="secondary" style={{ fontSize: 12 }}>{localSelectedPrj || t("total", { ns: "common" })}</Text>}
          >
            <Table 
              size="small" 
              dataSource={mockHistory} 
              pagination={false}
              columns={[
                { title: t("dashboard.history.no"), dataIndex: "no", width: 60 },
                { title: t("dashboard.history.date"), dataIndex: "date" },
                { title: t("dashboard.passRate"), dataIndex: "passRate", align: "right" },
                { title: t("dashboard.history.inspector"), dataIndex: "inspector" },
              ]}
            />
          </Card>
        </Col>
      </Row>
    </div>
  );
};

export default QualityDashboard;
