import React, { useState, useMemo } from "react";
import { useTranslation } from "react-i18next";
import { 
  Row, Col, Card, Table, Segmented, Space, 
  Tag, Typography, Button, theme, Progress, Tooltip, App
} from "antd";
import { 
  CheckCircleFilled, CloseCircleFilled, 
  QuestionCircleOutlined, InfoCircleOutlined,
  PlayCircleOutlined, ExclamationCircleOutlined,
  FileSearchOutlined
} from "@ant-design/icons";
import ReactECharts from "echarts-for-react";

const { useToken } = theme;
const { Title, Text } = Typography;

interface Props {
  projectId: string;
}

// --- Data Integrity Mock Generator ---
const getIntegrityData = (projectId: string) => {
  const data: Record<string, any[]> = {
    "1": [
      { key: "1", fileNm: "road_scene_001.json", result: "pass", schema: "OK", bounds: "OK", classMatch: "OK", empty: "OK" },
      { key: "2", fileNm: "road_scene_002.json", result: "fail", schema: "OK", bounds: "ERR", classMatch: "OK", empty: "OK" },
      { key: "3", fileNm: "road_scene_003.json", result: "pending", schema: "-", bounds: "-", classMatch: "-", empty: "-" },
    ],
    "3": [
      { key: "1", fileNm: "mri_01.xml", result: "fail", schema: "ERR", bounds: "OK", classMatch: "OK", empty: "OK" },
      { key: "2", fileNm: "mri_02.xml", result: "pass", schema: "OK", bounds: "OK", classMatch: "OK", empty: "OK" },
    ]
  };
  return data[projectId] || data["1"];
};

const AccuracyAnalysis: React.FC<Props> = ({ projectId }) => {
  const { token } = useToken();
  const { t } = useTranslation(["quality", "common"]);
  const { message } = App.useApp();
  const [viewMode, setViewMode] = useState<string>("basic");
  const [checking, setChecking] = useState(false);

  const currentData = useMemo(() => getIntegrityData(projectId), [projectId]);

  const handleRunCheck = () => {
    setChecking(true);
    setTimeout(() => {
      setChecking(false);
      message.success(t("accuracy.runCheck") + " " + t("confirm", { ns: "common" }));
    }, 1500);
  };

  const barOption = useMemo(() => ({
    tooltip: { trigger: 'axis', axisPointer: { type: 'shadow' } },
    grid: { left: '3%', right: '4%', bottom: '3%', containLabel: true },
    xAxis: { type: 'category', data: [t("accuracy.metrics.schema"), t("accuracy.metrics.bounds"), t("accuracy.metrics.classMatch"), t("accuracy.metrics.empty")] },
    yAxis: { type: 'value' },
    series: [{
      name: 'Error Count',
      type: 'bar',
      data: projectId === "1" ? [2, 15, 4, 1] : [12, 2, 1, 0],
      itemStyle: { color: token.colorError, borderRadius: [4, 4, 0, 0] }
    }]
  }), [projectId, t, token]);

  const columns = [
    { title: t("fileName", { ns: "common" }), dataIndex: "fileNm", key: "fileNm" },
    { 
      title: t("status", { ns: "common" }), 
      dataIndex: "result", 
      align: "center" as const,
      render: (v: string) => {
        if (v === "pass") return <Tag icon={<CheckCircleFilled />} color="success">{t("accuracy.result.pass")}</Tag>;
        if (v === "fail") return <Tag icon={<CloseCircleFilled />} color="error">{t("accuracy.result.fail")}</Tag>;
        return <Tag icon={<QuestionCircleOutlined />} color="default">{t("accuracy.result.pending")}</Tag>;
      }
    },
    { 
        title: t("accuracy.metrics.schema"), dataIndex: "schema", align: "center" as const, 
        render: (v: string) => v === "ERR" ? <Tag color="volcano">Schema Fail</Tag> : (v === "OK" ? <Text type="success">Valid</Text> : v) 
    },
    { 
        title: t("accuracy.metrics.bounds"), dataIndex: "bounds", align: "center" as const,
        render: (v: string) => v === "ERR" ? <Tag color="volcano" icon={<ExclamationCircleOutlined />}>Out of Bounds</Tag> : (v === "OK" ? <Text type="success">In-Bound</Text> : v) 
    },
    { 
        title: t("accuracy.metrics.classMatch"), dataIndex: "classMatch", align: "center" as const,
        render: (v: string) => v === "ERR" ? <Tag color="volcano">Class Mismatch</Tag> : (v === "OK" ? <Text type="success">Matched</Text> : v) 
    },
    { 
        title: t("accuracy.metrics.empty"), dataIndex: "empty", align: "center" as const,
        render: (v: string) => v === "ERR" ? <Tag color="volcano">Null Object</Tag> : (v === "OK" ? <Text type="success">OK</Text> : v)
    },
    { 
        title: t("common.action"), align: "center" as const, 
        render: () => <Button size="small" type="link" icon={<FileSearchOutlined />}>Log</Button> 
    }
  ];

  return (
    <div style={{ marginTop: 24 }}>
      <div style={{ display: "flex", justifyContent: "flex-end", marginBottom: 16 }}>
        <Button 
            type="primary" 
            icon={<PlayCircleOutlined />} 
            loading={checking}
            onClick={handleRunCheck}
        >
          {t("accuracy.runCheck")}
        </Button>
      </div>

      <Row gutter={[24, 24]}>
        <Col span={8}>
          <Card 
            variant="borderless"
            title={
              <Space>
                <InfoCircleOutlined />
                {t("accuracy.mode.detail")}
              </Space>
            }
          >
            <ReactECharts option={barOption} style={{ height: 300 }} />
            <div style={{ padding: "10px 20px" }}>
              <Text type="secondary" style={{ fontSize: 13 }}>
                {t("dashboard.passRate")}: <Text strong type="success">{projectId === "3" ? "88.2%" : "96.5%"}</Text>
              </Text>
              <Progress percent={projectId === "3" ? 88.2 : 96.5} size="small" strokeColor={token.colorSuccess} style={{ marginTop: 8 }} />
            </div>
          </Card>
        </Col>

        <Col span={16}>
          <Card 
            variant="borderless"
            title={t("accuracy.title")} 
            extra={
              <Segmented 
                options={[
                  { label: "전체 결과", value: "basic" },
                  { label: "오류만 보기", value: "error" }
                ]} 
                value={viewMode}
                onChange={(v) => setViewMode(v as string)}
              />
            }
          >
            <Table 
              size="small" 
              dataSource={currentData} 
              columns={columns}
              pagination={{ pageSize: 8 }}
            />
          </Card>
        </Col>
      </Row>
    </div>
  );
};

export default AccuracyAnalysis;
